-- ============================================================
-- AIRCRAFT (3) — each owned by a specific airline
-- ============================================================
INSERT INTO public."AIRCRAFT" (airline_id, model)
SELECT airline_id, 'Boeing 777-300ER'
FROM public."AIRLINE" WHERE iata_code = 'KE'
ON CONFLICT DO NOTHING;

INSERT INTO public."AIRCRAFT" (airline_id, model)
SELECT airline_id, 'Airbus A350-900'
FROM public."AIRLINE" WHERE iata_code = 'DL'
ON CONFLICT DO NOTHING;

INSERT INTO public."AIRCRAFT" (airline_id, model)
SELECT airline_id, 'Airbus A380-800'
FROM public."AIRLINE" WHERE iata_code = 'EK'
ON CONFLICT DO NOTHING;


-- ============================================================
-- SEAT_CLASS (3 classes × 3 aircraft = 9 rows)
-- The trigger trg_auto_generate_seats will auto-populate
-- SEAT_INVENTORY for each row inserted here.
-- ============================================================

-- Korean Air Boeing 777-300ER
INSERT INTO public."SEAT_CLASS" (class_name, aircraft_id, seat_count, price)
SELECT 'First',    aircraft_id, 2, 1500.00 FROM public."AIRCRAFT" ac JOIN public."AIRLINE" al ON al.airline_id = ac.airline_id WHERE al.iata_code = 'KE' AND ac.model = 'Boeing 777-300ER'
ON CONFLICT (aircraft_id, class_name) DO NOTHING;

INSERT INTO public."SEAT_CLASS" (class_name, aircraft_id, seat_count, price)
SELECT 'Business', aircraft_id, 2, 800.00  FROM public."AIRCRAFT" ac JOIN public."AIRLINE" al ON al.airline_id = ac.airline_id WHERE al.iata_code = 'KE' AND ac.model = 'Boeing 777-300ER'
ON CONFLICT (aircraft_id, class_name) DO NOTHING;

