-- ============================================================
-- FLIGHT_SCHEDULE (4 schedules)
-- ============================================================
INSERT INTO public."FLIGHT_SCHEDULE" (
  aircraft_id, depart_airport_iata, dest_airport_iata,
  flight_number, depart_time, arrival_time,
  days_of_week, valid_from, valid_until
)
SELECT
  ac.aircraft_id, 'ICN', 'JFK', 'KE001',
  '10:00', '10:00', 'Mon,Wed,Fri',
  '2026-05-01', '2026-08-31'
FROM public."AIRCRAFT" ac
JOIN public."AIRLINE" al ON al.airline_id = ac.airline_id
WHERE al.iata_code = 'KE' AND ac.model = 'Boeing 777-300ER'
ON CONFLICT DO NOTHING;

INSERT INTO public."FLIGHT_SCHEDULE" (
  aircraft_id, depart_airport_iata, dest_airport_iata,
  flight_number, depart_time, arrival_time,
  days_of_week, valid_from, valid_until
)
SELECT
  ac.aircraft_id, 'JFK', 'LHR', 'DL100',
  '19:00', '07:00', 'Tue,Thu,Sat',
  '2026-05-01', '2026-08-31'
