-- ============================================================
-- STOPOVER — EK350: ICN → DXB (layover 2h) → LHR
-- ============================================================
INSERT INTO public."STOPOVER" (
  schedule_id, airport_iata,
  arrival_time_offset, departure_time_offset, stop_order
)
SELECT
  schedule_id, 'DXB',
  interval '9 hours', interval '11 hours', 1
FROM public."FLIGHT_SCHEDULE"
WHERE flight_number = 'EK350'
ON CONFLICT (schedule_id, stop_order) DO NOTHING;


